import { AgentProjectsClient } from '@azure/ai-projects';
import { InvoiceSchema } from './schemas';

const client = new AgentProjectsClient('project-api-key');
const project = await client.getProject('extraction-project');

const thread = await project.createThread();
const result = await project.runAgent({
  agentName: 'invoice-extractor',
  threadId: thread.id,
  input: 'Extract invoice data from document text',
  outputSchema: InvoiceSchema,
  model: 'gpt-4o'
});

console.log(result.output);

import { z } from 'zod';

const InvoiceSchema = z.object({
  invoice_number: z.string().min(1),
  total_amount: z.number().positive(),
  date: z.string().regex(/^\d{4}-\d{2}-\d{2}$/)
});

function validateExtraction(result: any) {
  const parsed = InvoiceSchema.safeParse(result.output);
  if (!parsed.success) {
    throw new Error(`Schema violation: ${parsed.error.message}`);
  }
  return parsed.data;
}

